// Sections returns the unique set of section slugs present in Ops, sorted.
func Sections() []string {
	seen := map[string]struct{}{}
	for _, m := range Ops {
		seen[m.Section] = struct{}{}
	}
	out := make([]string, 0, len(seen))
	for s := range seen {
		out = append(out, s)
	}
	// stable order: simple insertion sort is fine for ~10 sections.
	for i := 1; i < len(out); i++ {
		for j := i; j > 0 && out[j-1] > out[j]; j-- {
			out[j], out[j-1] = out[j-1], out[j]
		}
	}
	return out
}
